  1	import React, { useMemo } from 'react';
  2	import { Link } from 'react-router-dom-v5-compat';
  3	import xbytes from 'xbytes';
  4	
  5	import VirtualMachineModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineModel';
  6	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
  7	import ComponentReady from '@kubevirt-utils/components/Charts/ComponentReady/ComponentReady';
  8	import { getUtilizationQueries } from '@kubevirt-utils/components/Charts/utils/queries';
  9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 10	import { getResourceUrl } from '@kubevirt-utils/resources/shared';
 11	import { isEmpty } from '@kubevirt-utils/utils/utils';
 12	import { PrometheusEndpoint, usePrometheusPoll } from '@openshift-console/dynamic-plugin-sdk';
 13	import { Button, ButtonVariant, Popover, Text, TextVariants } from '@patternfly/react-core';
 14	import useDuration from '@virtualmachines/details/tabs/metrics/hooks/useDuration';
 15	
 16	type NetworkUtilProps = {
 17	  vmi: V1VirtualMachineInstance;
 18	};
 19	
 20	const NetworkUtil: React.FC<NetworkUtilProps> = ({ vmi }) => {
 21	  const { t } = useKubevirtTranslation();
 22	  const { currentTime, duration } = useDuration();
 23	  const queries = React.useMemo(
 24	    () => getUtilizationQueries({ duration, obj: vmi }),
 25	    [vmi, duration],
 26	  );
 27	  const interfacesNames = useMemo(() => vmi?.spec?.domain?.devices?.interfaces, [vmi]);
 28	  const [networkIn] = usePrometheusPoll({
 29	    endpoint: PrometheusEndpoint?.QUERY,
 30	    endTime: currentTime,
 31	    namespace: vmi?.metadata?.namespace,
 32	    query: queries?.NETWORK_IN_USAGE,
 33	  });
 34	
 35	  const [networkTotal] = usePrometheusPoll({
 36	    endpoint: PrometheusEndpoint?.QUERY,
 37	    endTime: currentTime,
 38	    namespace: vmi?.metadata?.namespace,
 39	    query: queries?.NETWORK_TOTAL_BY_INTERFACE_USAGE,
 40	  });
 41	
 42	  const [networkOut] = usePrometheusPoll({
 43	    endpoint: PrometheusEndpoint?.QUERY,
 44	    endTime: currentTime,
 45	    namespace: vmi?.metadata?.namespace,
 46	    query: queries?.NETWORK_OUT_USAGE,
 47	  });
 48	  const networkInterfaceTotal = Number(networkTotal?.data?.result?.[0]?.value?.[1])?.toFixed(2);
 49	  const networkInData = +networkIn?.data?.result?.[0]?.value?.[1];
 50	  const networkOutData = +networkOut?.data?.result?.[0]?.value?.[1];
 51	  const totalTransferred = xbytes(networkInData + networkOutData || 0, {
 52	    fixed: 0,
 53	    iec: true,
 54	  });
 55	  const isReady = !isEmpty(networkInData) || !isEmpty(networkOutData);
 56	
 57	  return (
 58	    <div className="util network">
 59	      <div className="util-upper">
 60	        <div className="util-title">
 61	          {t('Network transfer')}
 62	          <Popover
 63	            bodyContent={
 64	              <div>
 65	                <Text component={TextVariants.h3}>{t('Network transfer breakdown')}</Text>
 66	                <Text component={TextVariants.h6}>{t('Top consumer')}</Text>
 67	                {interfacesNames?.map((networkInterface) => (
 68	                  <div className="network-popover" key={networkInterface?.name}>
 69	                    <Link
 70	                      to={`${getResourceUrl({
 71	                        model: VirtualMachineModel,
 72	                        resource: vmi,
 73	                      })}/metrics?network=${networkInterface?.name}`}
 74	                    >
 75	                      {networkInterface?.name}
 76	                    </Link>
 77	                    {networkInterface?.name === networkInterfaceTotal ? (
 78	                      <div className="text-muted">{`${networkInterfaceTotal} MBps`}</div>
 79	                    ) : (
 80	                      <div className="text-muted">
 81	                        {networkTotal?.data?.result?.map(
 82	                          (name) =>
 83	                            name?.metric?.interface === networkInterface?.name &&
 84	                            `${Number(name?.value?.[1])?.toFixed(2)} MBps`,
 85	                        )}
 86	                      </div>
 87	                    )}
 88	                  </div>
 89	                ))}
 90	                {interfacesNames?.length > 5 && (
 91	                  <Link
 92	                    to={`${getResourceUrl({
 93	                      model: VirtualMachineModel,
 94	                      resource: vmi,
 95	                    })}/metrics?network`}
 96	                  >
 97	                    {t('View more')}
 98	                  </Link>
 99	                )}
100	              </div>
101	            }
102	            position="bottom"
103	          >
104	            <div>
105	              <Button isInline variant={ButtonVariant.link}>
106	                {t('Breakdown by network')}
107	              </Button>
108	            </div>
109	          </Popover>
110	        </div>
111	
112	        <div className="util-summary" data-test-id="util-summary-network-transfer">
113	          <div className="util-summary-value">{`${totalTransferred}ps`}</div>
114	          <div className="util-summary-text text-muted network-value">
115	            <div>{t('Total')}</div>
116	          </div>
117	        </div>
118	      </div>
119	      <ComponentReady isReady={isReady}>
120	        <div className="network-metrics">
121	          <div className="network-metrics--row text-muted">
122	            <div className="network-metrics--row__sum">
123	              {`${xbytes(networkInData || 0, {
124	                fixed: 0,
125	              })}s`}
126	            </div>
127	            <div className="network-metrics--row__title">{t('In')}</div>
128	          </div>
129	          <div className="network-metrics--row text-muted">
130	            <div className="network-metrics--row__sum">
131	              {`${xbytes(networkOutData || 0, {
132	                fixed: 0,
133	              })}s`}
134	            </div>
135	            <div className="network-metrics--row__title">{t('Out')}</div>
136	          </div>
137	        </div>
138	      </ComponentReady>
139	    </div>
140	  );
141	};
142	
143	export default NetworkUtil;

